// Solution
var sqlQuery = function(products) {
  var result = [];
  var groupedProducts = {};
  for (var i = 0; i < products.length; i++) {
    var productName = products[i].product_name.toLowerCase();
    if (groupedProducts[productName]) {
      groupedProducts[productName].count++;
    } else {
      groupedProducts[productName] = {product_name: productName, count: 1};
    }
  }
  var sortedProducts = Object.values(groupedProducts).sort(function(a, b) {
    return b.count - a.count;
  });
  return sortedProducts;
};

solutions.python:
class Solution:
  def solve(self, products):
    result = {}
    for product in products:
      product_name = product['product_name'].lower()
      if product_name in result:
        result[product_name]['count'] += 1
      else:
        result[product_name] = {'product_name': product_name, 'count': 1}
    sortedProducts = sorted(result.values(), key=lambda x: x['count'], reverse=True)
    return sortedProducts;
